  stimulus_type = NULL,
  options = '[{"id":"A","text":"The most recent scientific evidence of the link between sugar consumption and Alzheimer’s disease was published in 2018; and it is generally accepted by the scientific community.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The most recent scientific evidence of the link between sugar consumption and Alzheimer’s disease was published in 2018, it is generally accepted by the scientific community.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The most recent scientific evidence of the link between sugar consumption and Alzheimer’s disease was published in 2018, however, it is generally accepted by the scientific community.","is_correct":true,"explanation":"Choice C matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The most recent scientific evidence of the link between sugar consumption and Alzheimer’s disease was published in 2018 because it is generally accepted by the scientific community.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'C',
  explanation = 'A comma splice occurs when two independent clauses are joined together only by a comma.  To correct a comma splice, the two clauses must be joined by a semicolon, a comma followed by a coordinating conjunction, or a period. Choice C is correct because it uses a comma followed by the coordinating conjunction "however" to separate the two independent clauses in the sentence.  Choice A is incorrect because the semicolon should be followed by a comma, not "and."  Choice B is incorrect because a comma alone cannot separate the two independent clauses in the sentence.  Choice D is incorrect because the word "because" is a subordinating conjunction, which should only be used to link a dependent clause to an independent clause. The passage states that "The following sentence contains a comma splice: "The most recent scientific evidence of the link between sugar consumpti…", which is the textual anchor for eliminating weaker choices. Choice C is correct because it aligns with that evidence: The most recent scientific evidence of the link between sugar consumption and Alzheimer’s disease wa…. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
